package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Constructor;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static class DummyRecord {
    public final int x;
    public DummyRecord(int x) { this.x = x; }
  }

  private static class DummyClass {}

  @BeforeAll
  static void setup() throws Exception {
    // Use reflection to set the private static final RECORD_HELPER field to a mock
    RecordHelper mockRecordHelper = mock(RecordHelper.class);
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() throws Exception {
    RecordHelper mockRecordHelper = getRecordHelperMock();
    when(mockRecordHelper.isRecord(DummyRecord.class)).thenReturn(true);

    assertTrue(ReflectionHelper.isRecord(DummyRecord.class));

    verify(mockRecordHelper).isRecord(DummyRecord.class);
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() throws Exception {
    RecordHelper mockRecordHelper = getRecordHelperMock();
    when(mockRecordHelper.isRecord(DummyClass.class)).thenReturn(false);

    assertFalse(ReflectionHelper.isRecord(DummyClass.class));

    verify(mockRecordHelper).isRecord(DummyClass.class);
  }

  private RecordHelper getRecordHelperMock() throws Exception {
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    return (RecordHelper) recordHelperField.get(null);
  }
}
